/**
 * create-checkout.js
 * Netlify Function - Stripe Checkout Session Creator
 *
 * POST /.netlify/functions/create-checkout
 * Body: { planId: "farr-40-full" }
 * Returns: { url: "https://checkout.stripe.com/..." }
 *
 * Sprint 5C: Reads plan_catalog.json (generated by build_site.py from boats.json)
 * instead of a hardcoded catalog. Adding a new purchasable plan is now a data-only
 * change via the admin portal — no code changes required.
 *
 * Required environment variables (set in Netlify UI):
 *   STRIPE_SECRET_KEY   - sk_live_... or sk_test_...
 *   SITE_URL            - https://farrdesign.com (no trailing slash)
 *   STRIPE_PRICE_*      - One per plan, referenced by stripePriceEnv in boats.json
 *
 * Demo/client-review mode (no Stripe keys required):
 *   STRIPE_MOCK=true    - bypasses Stripe, redirects to success page with mock session
 */

const fs = require('fs');
const path = require('path');

// Load the build-time generated plan catalog
// Falls back to empty catalog if file doesn't exist (no plans purchasable)
let PLAN_CATALOG;
try {
  PLAN_CATALOG = JSON.parse(
    fs.readFileSync(path.join(__dirname, '../../_data/plan_catalog.json'), 'utf-8')
  );
} catch (e) {
  console.warn('plan_catalog.json not found — no plans available for purchase');
  PLAN_CATALOG = {};
}

exports.handler = async function (event) {
  if (event.httpMethod !== 'POST') {
    return { statusCode: 405, body: JSON.stringify({ error: 'Method not allowed' }) };
  }

  let planId;
  try {
    const body = JSON.parse(event.body || '{}');
    planId = body.planId;
  } catch (e) {
    return { statusCode: 400, body: JSON.stringify({ error: 'Invalid request body' }) };
  }

  const plan = PLAN_CATALOG[planId];
  if (!plan) {
    return { statusCode: 404, body: JSON.stringify({ error: 'Plan not found: ' + planId }) };
  }

  // Resolve the Stripe price ID from the environment variable name stored in boats.json
  const priceId = process.env[plan.stripePriceEnv];
  if (!priceId) {
    console.error(`Stripe env var ${plan.stripePriceEnv} not set for plan ${planId}`);
    return {
      statusCode: 500,
      body: JSON.stringify({ error: 'Stripe not configured for this plan. Please contact support.' })
    };
  }

  const siteUrl = process.env.SITE_URL || 'https://farrdesign.com';

  /* ---- MOCK MODE: set STRIPE_MOCK=true in Netlify env vars for client demos ---- */
  if (process.env.STRIPE_MOCK === 'true') {
    const mockSessionId = 'mock_session_' + Date.now() + '_' + planId.replace(/-/g, '_');
    const successUrl = siteUrl + '/purchase-success.html?session_id=' + mockSessionId;
    return {
      statusCode: 200,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ url: successUrl })
    };
  }
  /* ---- END MOCK MODE ---- */

  const stripe = require('stripe')(process.env.STRIPE_SECRET_KEY);

  try {
    const session = await stripe.checkout.sessions.create({
      mode: 'payment',
      line_items: [{ price: priceId, quantity: 1 }],
      payment_intent_data: {
        metadata: { planId: planId, planName: plan.name }
      },
      metadata: { planId: planId, planName: plan.name },
      success_url: siteUrl + '/purchase-success.html?session_id={CHECKOUT_SESSION_ID}',
      cancel_url: siteUrl + '/design-plans.html?cancelled=1',
      customer_creation: 'always',
      billing_address_collection: 'auto',
      allow_promotion_codes: false
    });

    return {
      statusCode: 200,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ url: session.url })
    };

  } catch (err) {
    console.error('Stripe error:', err.message);
    return {
      statusCode: 500,
      body: JSON.stringify({ error: 'Checkout creation failed. Please try again.' })
    };
  }
};
